Create `apps/client/src/layers/features/agents-list/ui/AgentsList.tsx` — the list container that renders `AgentRow` components with optional namespace grouping, and integrates `AgentFilterBar`.

## Component Interface

```tsx
interface AgentsListProps {
  agents: AgentManifest[];
  isLoading: boolean;
}
```

## Implementation

```tsx
import { useMemo, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Skeleton } from '@/layers/shared/ui/skeleton';
import { ScrollArea } from '@/layers/shared/ui/scroll-area';
import { useSessions } from '@/layers/entities/session';
import { useMeshAgentHealth } from '@/layers/entities/mesh';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';
import { AgentRow } from './AgentRow';
import { AgentFilterBar } from './AgentFilterBar';

export function AgentsList({ agents, isLoading }: AgentsListProps) {
  const [filteredAgents, setFilteredAgents] = useState<AgentManifest[]>(agents);
  const [groupByNamespace, setGroupByNamespace] = useState(false);
  const { data: sessions = [] } = useSessions();

  // Auto-enable grouping when >1 namespace
  const namespaces = useMemo(
    () => [...new Set(agents.map((a) => a.namespace).filter(Boolean))],
    [agents]
  );
  const shouldGroup = groupByNamespace || namespaces.length > 1;

  // Group agents by namespace
  const grouped = useMemo(() => {
    if (!shouldGroup) return { '': filteredAgents };
    return filteredAgents.reduce<Record<string, AgentManifest[]>>((acc, agent) => {
      const ns = agent.namespace || 'default';
      (acc[ns] ??= []).push(agent);
      return acc;
    }, {});
  }, [filteredAgents, shouldGroup]);

  // Compute session counts per agent
  const sessionCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    for (const agent of agents) {
      counts[agent.id] = sessions.filter(
        (s) => s.cwd === agent.projectPath || s.dir === agent.projectPath
      ).length;
    }
    return counts;
  }, [agents, sessions]);

  if (isLoading) {
    return (
      <div className="space-y-3 p-4">
        {Array.from({ length: 3 }).map((_, i) => (
          <Skeleton key={i} className="h-14 w-full rounded-xl" />
        ))}
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      <AgentFilterBar agents={agents} onFilterChange={setFilteredAgents} />
      <ScrollArea className="flex-1">
        <div className="space-y-2 p-4 pt-0">
          {Object.entries(grouped).map(([namespace, groupAgents]) => (
            <div key={namespace}>
              {shouldGroup && namespace && (
                <h3 className="text-muted-foreground mb-2 mt-4 first:mt-0 text-[10px] font-medium tracking-widest uppercase">
                  {namespace}
                </h3>
              )}
              <motion.div
                initial="hidden"
                animate="visible"
                variants={{
                  visible: { transition: { staggerChildren: 0.04 } },
                  hidden: {},
                }}
                className="space-y-2"
              >
                {groupAgents.map((agent) => (
                  <motion.div
                    key={agent.id}
                    variants={{
                      hidden: { opacity: 0, y: 8 },
                      visible: { opacity: 1, y: 0 },
                    }}
                    transition={{ duration: 0.15 }}
                  >
                    <AgentRow
                      agent={agent}
                      sessionCount={sessionCounts[agent.id] ?? 0}
                      healthStatus="active"
                      lastActive={null}
                    />
                  </motion.div>
                ))}
              </motion.div>
            </div>
          ))}
        </div>
      </ScrollArea>
    </div>
  );
}
```

Note: Health status and last active are placeholder values. In a follow-up, wire up `useMeshAgentHealth` per agent to derive real status. For now, default to `'active'` and `null` to keep the component functional.

